SELECT COUNT(*) AS active_model_count
FROM climate_models
WHERE model_status = 'active';

SELECT AVG(mld_value) AS average_mld_value
FROM mld_values
WHERE scenario_id = 0 AND variable_id = 1;

SELECT model_name
FROM climate_models
WHERE model_id = 1;

SELECT projection_year, mld_value, std_dev
FROM mld_values
WHERE projection_id = 1;

SELECT AVG(mld_value) AS avg_mld, MAX(std_dev) AS max_std_dev
FROM mld_values
WHERE scenario_id = 0 AND variable_id = 1;

SELECT DISTINCT variable_name
FROM variables
WHERE variable_status = 'active';
